+    fn markdown_span_fg_for_text(
+        lines: &[ftui::text::Line],
+        needle: &str,
+    ) -> Option<ftui::render::cell::PackedRgba> {
+        for line in lines {
+            for span in line.spans() {
+                if span.content.as_ref().contains(needle) {
+                    return span.style.as_ref().and_then(|style| style.fg);
+                }
+            }
+        }
+        None
+    }
